import requests, json

def main():
    url = 'http://127.0.0.1:5000/'
    headers = {'Content-Type': 'application/json'}

    # Login
    login_data = {
        "username": "admin", 
        "password": "<PASSWORD>"
    }
    response = requests.post(url + 'login', data=json.dumps(login_data), headers=headers)
    print('Login response: ', json.loads(response.text))

    # Protected endpoint 1
    protected_endpoint_1_data = {
        "token": json.loads(response.text)['token']
    }
    response = requests.post(url + 'protected-endpoint-1', data=json.dumps(protected_endpoint_1_data), headers=headers)
    print('Protected endpoint 1 response: ', json.loads(response.text))

    # Protected endpoint 2
    protected_endpoint_2_data = {
        "token": json.loads(response.text)['token']
    }
    response = requests.post(url + 'protected-endpoint-2', data=json.dumps(protected_endpoint_2_data), headers=headers)
    print('Protected endpoint 2 response: ', json.loads(response.text))

if __name__ == '__main__':
    main()